#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define drep(a,b,c) for(register int c=(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=2e5+10;int n,a[N];
inline bool check(int k)
{
	for(int l=n,r=n;l>=1&&r<=2*n-1;--l,++r)
	{
		if((a[l]>k&&a[l-1]>k)||(a[r]>k&&a[r+1]>k))return 0;
		if((a[l]<=k&&a[l-1]<=k)||(a[r]<=k&&a[r+1]<=k))return 1;
	}return a[1]<=k;
}
int main()
{
//	freopen("dt.txt","r",stdin);freopen("1l.txt","w",stdout);
	n=read();int l=1,r=0,res=0,mid;rep(1,2*n-1,i)r=max(r,a[i]=read());//printf("%d\n",check(8));
	while(l<=r)check(mid=(l+r)>>1)?(r=mid-1,res=mid):(l=mid+1);printf("%d\n",res);return 0;
}
